# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance
        
    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False
            
    def withdrawal(self, amount):
        if amount <= self.balance and amount > 0:
            self.balance -= amount
            return True
        else:
            return False

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}
        
    def add_account(self, account):
        if not isinstance(account, Account):
            raise ValueError('Invalid account type')
            
        if account.id in self.accounts:
            raise KeyError('Account ID already exists')
            
        self.accounts[account.id] = account
        
    def process_transaction(self, id, transaction):
        # Transaction should be a tuple (operation, amount) where operation is 'deposit' or 'withdrawal'
        if not isinstance(transaction, tuple) or len(transaction) != 2:
            raise ValueError('Invalid transaction format')
            
        operation, amount = transaction
        
        account = self.accounts.get(id)
        
        if not account:
            raise KeyError('Account ID does not exist')
            
        if operation == 'deposit':
            return account.deposit(amount)
        elif operation == 'withdrawal':
            return account.withdrawal(amount)
        else:
            raise ValueError("Operation must be either 'deposit' or 'withdrawal'")